using System;
using System.Collections;
using UnityEngine;

/// <summary>
/// Mapa-Múndi (GDD "Navegação"): controla a "bola de luz" que representa o
/// jogador no Mapa-Múndi. Move-se ao longo de um <see cref="WorldMapConnection"/>
/// de cada vez, a uma velocidade configurável no Inspector
/// (<see cref="speed"/>), e PÁRA SEMPRE em cada <see cref="WorldMapNode"/> —
/// nunca salta nós, mesmo que já estejam desbloqueados.
///
/// <see cref="WorldMapController"/> decide PARA ONDE a bola viaja (com base no
/// analógico esquerdo e na regra de alcançabilidade dos nós); este componente
/// só sabe mover-se de um extremo ao outro de uma ligação e avisar quando
/// chega/quando o progresso muda (para a câmara e transições visuais).
/// </summary>
public class LightBallController : MonoBehaviour
{
    [Header("Velocidade")]
    [Tooltip("Velocidade da bola de luz ao longo dos ramos, em unidades de mundo por segundo. Ajustar aqui controla o ritmo de toda a navegação do Mapa-Múndi.")]
    [Min(0.01f)]
    public float speed = 4f;

    [Header("Estado Inicial (apenas testes no Editor)")]
    [Tooltip("Nó onde a bola aparece ao iniciar, se WorldMapController não a reposicionar primeiro. Em jogo normal, WorldMapController.WarpToCurrentArea define a posição correcta ao abrir o mapa.")]
    public WorldMapNode startingNode;

    /// <summary>Nó onde a bola está parada (válido apenas quando !IsMoving).</summary>
    public WorldMapNode CurrentNode { get; private set; }

    /// <summary>Ligação que a bola está a atravessar (válido apenas enquanto IsMoving).</summary>
    public WorldMapConnection CurrentConnection { get; private set; }

    /// <summary>Progresso 0-1 ao longo de CurrentConnection (0 = fromNode, 1 = toNode), válido apenas enquanto IsMoving.</summary>
    public float Progress { get; private set; }

    public bool IsMoving { get; private set; }

    /// <summary>Disparado quando a bola chega a um nó e PÁRA — em todos os nós, mesmo já desbloqueados. WorldMapController abre o painel automático aqui.</summary>
    public event Action<WorldMapNode> ArrivedAtNode;

    /// <summary>Disparado a cada frame de movimento com (ligação, progresso 0-1) — usado pela câmara (WorldMapCameraRig) e pela transição visual entre regiões.</summary>
    public event Action<WorldMapConnection, float> ProgressChanged;

    private Coroutine moveRoutine;

    private void Start()
    {
        if (CurrentNode == null && startingNode != null)
            WarpToNode(startingNode);
    }

    /// <summary>Posiciona a bola instantaneamente num nó, sem animação (usado ao abrir o mapa — a bola "aparece" no nó da área actual).</summary>
    public void WarpToNode(WorldMapNode node)
    {
        if (node == null) return;

        StopMoving();
        CurrentNode = node;
        CurrentConnection = null;
        Progress = 0f;
        transform.position = node.transform.position;

        ArrivedAtNode?.Invoke(CurrentNode);
    }

    /// <summary>
    /// Move a bola ao longo de "connection", do nó actual para "targetNode"
    /// (o outro extremo dessa ligação). Devolve false se a bola já estiver em
    /// movimento, ou se "connection" não ligar ao nó onde a bola está parada.
    /// </summary>
    public bool TravelAlong(WorldMapConnection connection, WorldMapNode targetNode)
    {
        if (IsMoving || connection == null || targetNode == null || CurrentNode == null) return false;
        if (CurrentNode != connection.fromNode && CurrentNode != connection.toNode) return false;
        if (targetNode != connection.fromNode && targetNode != connection.toNode) return false;
        if (targetNode == CurrentNode) return false;

        moveRoutine = StartCoroutine(MoveRoutine(connection, targetNode));
        return true;
    }

    /// <summary>Pára o movimento imediatamente (sem chegar a um nó) — uso raro, ex: cancelar uma viagem por uma cutscene.</summary>
    public void StopMoving()
    {
        if (moveRoutine != null) StopCoroutine(moveRoutine);
        moveRoutine = null;
        IsMoving = false;
    }

    private IEnumerator MoveRoutine(WorldMapConnection connection, WorldMapNode targetNode)
    {
        IsMoving = true;
        CurrentConnection = connection;

        bool forward = targetNode == connection.toNode;
        float length = Mathf.Max(0.001f, connection.GetLength());

        float t = forward ? 0f : 1f;
        float dir = forward ? 1f : -1f;

        Progress = t;
        transform.position = connection.GetPositionAtProgress(t);
        ProgressChanged?.Invoke(connection, t);

        while ((forward && t < 1f) || (!forward && t > 0f))
        {
            float step = (speed / length) * Time.deltaTime;
            t = Mathf.Clamp01(t + dir * step);
            Progress = t;

            transform.position = connection.GetPositionAtProgress(t);
            ProgressChanged?.Invoke(connection, t);

            yield return null;
        }

        CurrentNode = targetNode;
        CurrentConnection = null;
        IsMoving = false;
        moveRoutine = null;

        ArrivedAtNode?.Invoke(CurrentNode);
    }
}
